mapper.select:
SELECT b.id, v.name AS venue_name, b.booking_date, b.time_slots AS slots, b.status, b.created_at, b.purpose, b.p_count, b.contact_info, GROUP_CONCAT(e.name SEPARATOR ',') AS equipments FROM bookings b LEFT JOIN venues v ON b.venue_id = v.id LEFT JOIN booking_equipment be ON b.id = be.booking_id LEFT JOIN equipments e ON be.equipment_id = e.id WHERE b.venue_id = #{venueId} AND b.booking_date BETWEEN #{startDate} AND #{endDate} AND b.status != 4
AND b.status = #{status}
GROUP BY b.id ORDER BY b.created_at ASC

SELECT id, venue_id, user_id, booking_date, time_slots, status, purpose, p_count, contact_info, version, created_at, updated_at
FROM bookings
WHERE venue_id = #{venueId}
AND booking_date = #{bookingDate}
AND status = 2
AND (time_slots & #{mask}) != 0
AND id != #{bookingId}
